package com.app.cashtrackapp.models

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.app.cashtrackapp.database.classes.LancamentosHandler
import com.app.cashtrackapp.entity.EntryDataType
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

sealed class SubmitState {
    object Idle : SubmitState()
    object Submitting : SubmitState()
    object Success : SubmitState()
    data class Error(val message: String) : SubmitState()
}

class EntriesDataViewModel : ViewModel() {
    private val _submitState = MutableStateFlow<SubmitState>(SubmitState.Idle)
    val submitState: StateFlow<SubmitState> = _submitState

    fun submitEntry(type: String, value: Double, description: String, dateMillis: Long) {
        if (value <= 0.0) {
            _submitState.value = SubmitState.Error("Valor deve ser maior que 0")
            return
        }
        if (description.isBlank()) {
            _submitState.value = SubmitState.Error("Descrição não pode ser vazia")
            return
        }

        _submitState.value = SubmitState.Submitting

        val entry = EntryDataType(
            op = type,
            opDate = dateMillis,
            opDescription = description,
            opValue = value
        )

        LancamentosHandler.inserirLancamento(entry) { success, error ->
            viewModelScope.launch {
                if (success) {
                    _submitState.value = SubmitState.Success
                } else {
                    _submitState.value =
                        SubmitState.Error(error?.localizedMessage ?: "Erro ao salvar")
                }
            }
        }
    }

    fun resetState() {
        _submitState.value = SubmitState.Idle
    }
}

package com.app.cashtrackapp.models

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.app.cashtrackapp.database.classes.LancamentosHandler
import com.app.cashtrackapp.entity.EntryDataType
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

/**
 * SubmitState representa todos os ESTADOS POSSÍVEIS ao tentar salvar um lançamento.
 * 
 * É como um "semáforo" que avisa à tela o que está acontecendo:
 * - Idle (Parado) = esperando o usuário fazer algo
 * - Submitting (Enviando) = dados estão sendo salvos no Firebase
 * - Success (Sucesso) = dados foram salvos! Mostrar mensagem de sucesso
 * - Error (Erro) = algo deu errado. Mostrar mensagem de erro
 */
sealed class SubmitState {
    // Estado inicial: aguardando ação do usuário
    object Idle : SubmitState()

    // Estado intermediário: está enviando os dados para o Firebase agora
    object Submitting : SubmitState()

    // Estado final: dados foram salvos com sucesso!
    object Success : SubmitState()

    // Estado final: erro ao salvar. Carrega a mensagem de erro
    data class Error(val message: String) : SubmitState()
}

class EntriesDataViewModel : ViewModel() {
    private val _submitState = MutableStateFlow<SubmitState>(SubmitState.Idle)
    val submitState: StateFlow<SubmitState> = _submitState

    fun submitEntry(type: String, value: Double, description: String, dateMillis: Long) {
        if (value <= 0.0) {
            _submitState.value = SubmitState.Error("Valor deve ser maior que 0")
            return
        }
        if (description.isBlank()) {
            _submitState.value = SubmitState.Error("Descrição não pode ser vazia")
            return
        }

        _submitState.value = SubmitState.Submitting

        val entry = EntryDataType(
            op = type,
            opDate = dateMillis,
            opDescription = description,
            opValue = value
        )

        LancamentosHandler.inserirLancamento(entry) { success, error ->
            viewModelScope.launch {
                if (success) {
                    _submitState.value = SubmitState.Success
                } else {
                    _submitState.value =
                        SubmitState.Error(error?.localizedMessage ?: "Erro ao salvar")
                }
            }
        }
    }

    fun resetState() {
        _submitState.value = SubmitState.Idle
    }
}

package com.app.cashtrackapp.screens.ui

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier

@Composable
fun MainView(modifier: Modifier = Modifier) {
	// Exibe a tela de lançamentos por enquanto
	EntriesScreen(modifier = modifier)
}

// Import local to avoid unused imports when file opened in IDE
import androidx.compose.runtime.*
import androidx.compose.ui.*
import com.app.cashtrackapp.screens.ui.EntriesScreen

package com.app.cashtrackapp.utils

import com.app.cashtrackapp.entity.BankDataType
import com.google.firebase.database.FirebaseDatabase

// Helper simples para gravar entradas no Realtime Database
object db {
	private val database = FirebaseDatabase.getInstance()
	private val ref = database.getReference("entries")

	fun saveEntry(entry: BankDataType, onComplete: (Boolean, Exception?) -> Unit) {
		ref.push().setValue(entry).addOnCompleteListener { task ->
			onComplete(task.isSuccessful, task.exception)
		}
	}
}
